// App.js
import React, { useState, useEffect, createContext, useContext } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  Alert,
} from 'react-native';
import * as AuthSession from 'expo-auth-session';
import * as SecureStore from 'expo-secure-store';
import * as Crypto from 'expo-crypto';

// ============================================================
// SECURITY NOTE:
// - client_id is acceptable in mobile apps (it's a public identifier)
// - client_secret must NEVER be embedded in client-side code
// - We use PKCE flow which eliminates the need for a client_secret
//   on the client side
// ============================================================

const AUTH_CONFIG = {
  clientId: 'mobile_app_client_123',
  // NO client_secret here — this is intentional and correct.
  // If your OAuth provider requires a secret for token exchange,
  // route that through your backend server (see backendTokenEndpoint).
  authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
  tokenEndpoint: 'https://your-auth-server.com/oauth/token',
  revocationEndpoint: 'https://your-auth-server.com/oauth/revoke',
  // Your backend proxy that safely holds the client_secret
  backendTokenEndpoint: 'https://your-api-server.com/auth/token-exchange',
  redirectUri: AuthSession.makeRedirectUri({
    scheme: 'myapp',
    path: 'oauth/callback',
  }),
  scopes: ['openid', 'profile', 'email'],
};

const SECURE_STORE_KEYS = {
  ACCESS_TOKEN: 'auth_access_token',
  REFRESH_TOKEN: 'auth_refresh_token',
  TOKEN_EXPIRY: 'auth_token_expiry',
  ID_TOKEN: 'auth_id_token',
};

// ============================================================
// PKCE Utilities
// ============================================================

async function generateCodeVerifier() {
  const randomBytes = await Crypto.getRandomBytesAsync(32);
  return base64URLEncode(randomBytes);
}

async function generateCodeChallenge(verifier) {
  const digest = await Crypto.digestStringAsync(
    Crypto.CryptoDigestAlgorithm.SHA256,
    verifier,
    { encoding: Crypto.CryptoEncoding.BASE64 }
  );
  return base64URLEncodeString(digest);
}

function base64URLEncode(buffer) {
  const base64 = btoa(String.fromCharCode(...new Uint8Array(buffer)));
  return base64URLEncodeString(base64);
}

function base64URLEncodeString(str) {
  return str.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

async function generateState() {
  const randomBytes = await Crypto.getRandomBytesAsync(16);
  return base64URLEncode(randomBytes);
}

// ============================================================
// Secure Token Storage
// ============================================================

class TokenStorage {
  static async saveTokens({ accessToken, refreshToken, expiresIn, idToken }) {
    const expiryTime = Date.now() + expiresIn * 1000;

    await Promise.all([
      SecureStore.setItemAsync(SECURE_STORE_KEYS.ACCESS_TOKEN, accessToken),
      refreshToken
        ? SecureStore.setItemAsync(SECURE_STORE_KEYS.REFRESH_TOKEN, refreshToken)
        : Promise.resolve(),
      SecureStore.setItemAsync(
        SECURE_STORE_KEYS.TOKEN_EXPIRY,
        expiryTime.toString()
      ),
      idToken
        ? SecureStore.setItemAsync(SECURE_STORE_KEYS.ID_TOKEN, idToken)
        : Promise.resolve(),
    ]);
  }

  static async getAccessToken() {
    const [token, expiry] = await Promise.all([
      SecureStore.getItemAsync(SECURE_STORE_KEYS.ACCESS_TOKEN),
      SecureStore.getItemAsync(SECURE_STORE_KEYS.TOKEN_EXPIRY),
    ]);

    if (!token || !expiry) return null;

    // Check if token is expired (with 60s buffer)
    if (Date.now() >= parseInt(expiry, 10) - 60000) {
      return null; // Token expired, caller should refresh
    }

    return token;
  }

  static async getRefreshToken() {
    return SecureStore.getItemAsync(SECURE_STORE_KEYS.REFRESH_TOKEN);
  }

  static async clearTokens() {
    await Promise.all(
      Object.values(SECURE_STORE_KEYS).map((key) =>
        SecureStore.deleteItemAsync(key)
      )
    );
  }

  static async hasValidSession() {
    const token = await this.getAccessToken();
    return token !== null;
  }
}

// ============================================================
// Auth Service — PKCE Flow (no client_secret on client)
// ============================================================

class AuthService {
  static codeVerifier = null;
  static state = null;

  static async initiateAuthFlow() {
    // Generate PKCE values
    this.codeVerifier = await generateCodeVerifier();
    const codeChallenge = await generateCodeChallenge(this.codeVerifier);
    this.state = await generateState();

    const params = new URLSearchParams({
      client_id: AUTH_CONFIG.clientId,
      response_type: 'code',
      redirect_uri: AUTH_CONFIG.redirectUri,
      scope: AUTH_CONFIG.scopes.join(' '),
      state: this.state,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256',
    });

    return `${AUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;
  }

  /**
   * Exchange authorization code for tokens.
   * Option A: Direct PKCE exchange (if your OAuth server supports public clients)
   * Option B: Via backend proxy (if a client_secret is required)
   */
  static async exchangeCodeForTokens(code, returnedState) {
    // Validate state to prevent CSRF
    if (returnedState !== this.state) {
      throw new Error('State mismatch — possible CSRF attack');
    }

    // OPTION A: Direct PKCE exchange (preferred for public clients)
    // No client_secret needed because PKCE code_verifier proves the client
    try {
      const response = await fetch(AUTH_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          client_id: AUTH_CONFIG.clientId,
          code,
          redirect_uri: AUTH_CONFIG.redirectUri,
          code_verifier: this.codeVerifier,
        }).toString(),
      });

      if (!response.ok) {
        // If direct exchange fails, try backend proxy (Option B)
        return this.exchangeCodeViaBackend(code);
      }

      const tokenData = await response.json();
      await TokenStorage.saveTokens({
        accessToken: tokenData.access_token,
        refreshToken: tokenData.refresh_token,
        expiresIn: tokenData.expires_in,
        idToken: tokenData.id_token,
      });

      return tokenData;
    } catch (error) {
      // Fallback to backend proxy
      return this.exchangeCodeViaBackend(code);
    } finally {
      // Clear PKCE values after use
      this.codeVerifier = null;
      this.state = null;
    }
  }

  /**
   * OPTION B: Exchange code via your backend server.
   * The backend holds the client_secret securely and performs the exchange.
   */
  static async exchangeCodeViaBackend(code) {
    const response = await fetch(AUTH_CONFIG.backendTokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        code,
        redirect_uri: AUTH_CONFIG.redirectUri,
        code_verifier: this.codeVerifier,
      }),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(errorData.error || 'Token exchange failed');
    }

    const tokenData = await response.json();
    await TokenStorage.saveTokens({
      accessToken: tokenData.access_token,
      refreshToken: tokenData.refresh_token,
      expiresIn: tokenData.expires_in,
      idToken: tokenData.id_token,
    });

    return tokenData;
  }

  static async refreshAccessToken() {
    const refreshToken = await TokenStorage.getRefreshToken();
    if (!refreshToken) {
      throw new Error('No refresh token available');
    }

    // Refresh via backend proxy (which holds the secret)
    const response = await fetch(AUTH_CONFIG.backendTokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        grant_type: 'refresh_token',
        refresh_token: refreshToken,
      }),
    });

    if (!response.ok) {
      await TokenStorage.clearTokens();
      throw new Error('Token refresh failed');
    }

    const tokenData = await response.json();
    await TokenStorage.saveTokens({
      accessToken: tokenData.access_token,
      refreshToken: tokenData.refresh_token || refreshToken,
      expiresIn: tokenData.expires_in,
      idToken: tokenData.id_token,
    });

    return tokenData;
  }

  static async getValidAccessToken() {
    let token = await TokenStorage.getAccessToken();
    if (token) return token;

    // Token expired, try refresh
    try {
      const tokenData = await this.refreshAccessToken();
      return tokenData.access_token;
    } catch {
      return null; // User needs to re-authenticate
    }
  }

  static async logout() {
    const refreshToken = await TokenStorage.getRefreshToken();

    // Revoke token on server
    if (refreshToken) {
      try {
        await fetch(AUTH_CONFIG.backendTokenEndpoint, {
          method: 'DELETE',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ refresh_token: refreshToken }),
        });
      } catch {
        // Best effort revocation
      }
    }

    await TokenStorage.clearTokens();
  }
}

// ============================================================
// Authenticated HTTP Client
// ============================================================

class ApiClient {
  static async fetch(url, options = {}) {
    const token = await AuthService.getValidAccessToken();
    if (!token) {
      throw new Error('Not authenticated');
    }

    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        Authorization: `Bearer ${token}`,
      },
    });

    if (response.status === 401) {
      // Token might have been revoked server-side, try refresh once
      try {
        const newTokenData = await AuthService.refreshAccessToken();
        return fetch(url, {
          ...options,
          headers: {
            ...options.headers,
            Authorization: `Bearer ${newTokenData.access_token}`,
          },
        });
      } catch {
        await TokenStorage.clearTokens();
        throw new Error('Session expired');
      }
    }

    return response;
  }
}

// ============================================================
// Auth Context
// ============================================================

const AuthContext = createContext(null);

function AuthProvider({ children }) {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [user, setUser] = useState(null);

  useEffect(() => {
    checkExistingSession();
  }, []);

  async function checkExistingSession() {
    try {
      const hasSession = await TokenStorage.hasValidSession();
      if (hasSession) {
        setIsAuthenticated(true);
        await fetchUserProfile();
      }
    } catch {
      // No valid session
    } finally {
      setIsLoading(false);
    }
  }

  async function fetchUserProfile() {
    try {
      const response = await ApiClient.fetch(
        'https://your-auth-server.com/oauth/userinfo'
      );
      if (response.ok) {
        const userData = await response.json();
        setUser(userData);
      }
    } catch {
      // Profile fetch failed
    }
  }

  async function login() {
    try {
      setIsLoading(true);
      const authUrl = await AuthService.initiateAuthFlow();

      const result = await AuthSession.startAsync({
        authUrl,
        returnUrl: AUTH_CONFIG.redirectUri,
      });

      if (result.type === 'success' && result.params.code) {
        await AuthService.exchangeCodeForTokens(
          result.params.code,
          result.params.state
        );
        setIsAuthenticated(true);
        await fetchUserProfile();
      } else if (result.type === 'error') {
        Alert.alert('Authentication Error', result.params?.error_description || 'Login failed');
      }
    } catch (error) {
      Alert.alert('Error', error.message);
    } finally {
      setIsLoading(false);
    }
  }

  async function logout() {
    try {
      setIsLoading(true);
      await AuthService.logout();
      setIsAuthenticated(false);
      setUser(null);
    } catch (error) {
      Alert.alert('Error', 'Logout failed');
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <AuthContext.Provider
      value={{ isAuthenticated, isLoading, user, login, logout, ApiClient }}
    >
      {children}
    </AuthContext.Provider>
  );
}

function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context;
}

